1: const std = @import("std");
2: const assert = std.debug.assert;
3: const expectEqual = std.testing.expectEqual;
4: 
5: const Diacritic = enum(u8) {
6:     empty, // nguyên âm không dấu.
7:     circumflex, // dấu nón: â, ô, ê.
8:     horn, // dấu móc: ư, ơ.
9:     breve, // dấu ă.
10: };
11: 
12: const Tone = enum(u8) {
13:     level, // thanh ngang, không dấu.
14:     rising, // sắc.
15:     falling, // huyền.
16:     dipping_rising, // hỏi.
17:     rising_glottalized, // ngã.
18:     falling_glottalized, // nặng.
19: };
20: 
21: const Span = extern struct {
22:     // Alphabet ASCII character, could be lowercase or uppercase.
23:     base: u8,
24:     // By default, it's plain alphabet character.
25:     diacritic: Diacritic = Diacritic.empty,
26:     // By default, no tone is placed.
27:     tone: Tone = Tone.level,
28: 
29:     pub fn init(base: u8) Span {
30:         // Only allow a-zA-Z.
31:         assert(std.ascii.isAlphabetic(base));
32:         return .{ .base = base };
33:     }
34: };
35: 
36: test "expect Span.init allows alphabet characters" {
37:     // Act
38:     const c = Span.init('a');
39:     expectEqual('a', c.base);
40:     expectEqual(Diacritic.empty, c.diacritic);
41:     expectEqual(Tone.level, c.tone);
42: }
43: 
44: const InputMode = enum(u8) {
45:     // By pass Vietnamese input processing and append the character as is.
46:     literal,
47:     // Process Vietnamese input in Telex input method.
48:     telex,
49: };
50: 
51: const State = extern struct {
52:     // The effective buffer to process Vietnamese input. we will skip processing if the buffer
53:     // longer than 16.
54:     buffer_effective: [16]Span,
55:     // The maximum buffer length that the engine still keeps the effective buffer, after the maximum
56:     // value (256), we will reset the effective buffer and this value.
57:     buffer_length: u8,
58:     // Mark the position (inclusive) in buffer where we will switch to literal mode (due to manually
59:     // switch, input cancellation, exceed effective buffer). This value is independent from mode and
60:     // has higher priority, e.g. if the mode is `telex` but the engine is working on position on or
61:     // after literal index, the engine will skip Vietnamese input processing (we only count positive
62:     // value, -1 mean no literal index).
63:     literal_start_index: i8,
64:     // Determine if we will process input in the specified mode (Telex) or append the character as is.
65:     mode: InputMode = InputMode.literal,
66: };

